from typing import List
from queue import Queue

class Node:
    def __init__(self, val=None, next=None):
        self.val = val
        self.next = next

class Solution:
    def solve(self, head1: Node, head2: Node, target: int) -> Node:
        merged = self.merge(head1, head2)
        return self.deleteNodes(merged, target)

    def merge(self, p1: Node, p2: Node): 
        if p1 is None:
            return p2
        if p2 is None:
            return p1
        if p1.val >= p2.val:
            p1.next = self.merge(p1.next, p2)
            return p1
        else:
            p2.next = self.merge(p1, p2.next)
            return p2

    def deleteNodes(self, head: Node, target: int):
        dummy = Node(0)
        dummy.next = head
        prev, p = dummy, head
        while p is not None:
            if p.val < target:
                prev = p
                p = p.next
            else:
                prev.next = p.next
                p = p.next
        return dummy.next

