#include <iostream>
#include <queue>
#include <vector>
using namespace std;

struct Node {
    int val;
    Node* next;
    Node(int val, Node* next) : val(val), next(next) {}
};

class Solution {
public:
    Node* solve(Node* head1, Node* head2, int target) {
        Node* merged = merge(head1, head2);
        return deleteNodes(merged, target);
    }

    Node* merge(Node* p1, Node* p2) {
        if (p1 == nullptr) return p2;
        if (p2 == nullptr) return p1;
        if (p1->val >= p2->val) {
            p1->next = merge(p1->next, p2);
            return p1;
        } else {
            p2->next = merge(p1, p2->next);
            return p2;
        }
    }

    Node* deleteNodes(Node* head, int target) {
        Node dummy(0);
        dummy.next = head;
        Node* prev = &dummy;
        Node* p = head;
        while (p != nullptr) {
            if (p->val < target) {
                prev = p;
                p = p->next;
            } else {
                prev->next = p->next;
                p = p->next;
            }
        }
        return dummy.next;
    }
};
